"use client";

import * as React from "react";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

type TemplateId = "two-zone-vertical" | "two-zone-horizontal" | "five-zone";

interface Template {
  id: TemplateId;
  name: string;
  description: string;
  zones: string[];
  diagram: React.ReactNode;
}


const twoZoneVerticalDiagram = (
  <svg viewBox="0 0 160 90" xmlns="http://www.w3.org/2000/svg" className="w-full h-full">
    <rect x="0" y="0" width="160" height="72" fill="#e2e8f0" rx="2" />
    <text x="80" y="36" textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#64748b" fontFamily="sans-serif">
      Content
    </text>
    <rect x="0" y="74" width="160" height="16" fill="#cbd5e1" rx="2" />
    <text x="80" y="82" textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#64748b" fontFamily="sans-serif">
      Ticker
    </text>
  </svg>
);

const twoZoneHorizontalDiagram = (
  <svg viewBox="0 0 160 90" xmlns="http://www.w3.org/2000/svg" className="w-full h-full">
    <rect x="0" y="0" width="105" height="90" fill="#e2e8f0" rx="2" />
    <text x="52" y="45" textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#64748b" fontFamily="sans-serif">
      Content
    </text>
    <rect x="107" y="0" width="53" height="90" fill="#cbd5e1" rx="2" />
    <text x="133" y="45" textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#64748b" fontFamily="sans-serif">
      Side
    </text>
  </svg>
);

const fiveZoneDiagram = (
  <svg viewBox="0 0 160 90" xmlns="http://www.w3.org/2000/svg" className="w-full h-full">
    <rect x="0" y="0" width="105" height="62" fill="#e2e8f0" rx="2" />
    <text x="52" y="31" textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#64748b" fontFamily="sans-serif">
      Content
    </text>
    <rect x="107" y="0" width="53" height="28" fill="#cbd5e1" rx="2" />
    <text x="133" y="14" textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#64748b" fontFamily="sans-serif">
      Clock
    </text>
    <rect x="107" y="30" width="53" height="30" fill="#bfdbfe" rx="2" />
    <text x="133" y="45" textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#64748b" fontFamily="sans-serif">
      Weather
    </text>
    <rect x="0" y="64" width="105" height="26" fill="#ddd6fe" rx="2" />
    <text x="52" y="77" textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#64748b" fontFamily="sans-serif">
      Ticker
    </text>
    <rect x="107" y="62" width="53" height="28" fill="#fde68a" rx="2" />
    <text x="133" y="76" textAnchor="middle" dominantBaseline="middle" fontSize="9" fill="#64748b" fontFamily="sans-serif">
      Image
    </text>
  </svg>
);

const templates: Template[] = [
  {
    id: "two-zone-vertical",
    name: "Two Zone Vertical",
    description: "Main content area with a ticker bar along the bottom.",
    zones: [
      "Main Content — assign a playlist",
      "Ticker — assign ticker content",
    ],
    diagram: twoZoneVerticalDiagram,
  },
  {
    id: "two-zone-horizontal",
    name: "Two Zone Horizontal",
    description: "Content on the left with a sidebar column on the right.",
    zones: [
      "Left Content — assign a playlist",
      "Right Column — assign a playlist",
    ],
    diagram: twoZoneHorizontalDiagram,
  },
  {
    id: "five-zone",
    name: "5 Zone",
    description: "Rich layout with dedicated zones for content, clock, weather, ticker, and image.",
    zones: [
      "Main Content — assign a playlist",
      "Clock — clock widget",
      "Weather — weather widget",
      "Ticker — assign ticker content",
      "Image — assign an image",
    ],
    diagram: fiveZoneDiagram,
  },
];

export function CreateLayoutPage() {
  const [name, setName] = React.useState("");
  const [selectedTemplate, setSelectedTemplate] = React.useState<TemplateId | null>(null);

  const activeTemplate = templates.find((t) => t.id === selectedTemplate) ?? null;

  return (
    <div className="flex flex-col gap-6 pt-4 max-w-3xl">
      <div className="flex flex-col gap-1">
        <h1 className="text-xl font-semibold">Create Layout</h1>
        <p className="text-sm text-muted-foreground">
          Choose a template and give your layout a name.
        </p>
      </div>

      <div className="flex flex-col gap-2">
        <Label htmlFor="layout-name">Layout Name</Label>
        <Input
          id="layout-name"
          placeholder="e.g. Lobby Screen"
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="max-w-sm"
        />
      </div>

      <div className="flex flex-col gap-3">
        <p className="text-sm font-medium">Template</p>
        <div className="grid grid-cols-2 gap-4">
          {templates.map((template) => {
            const isSelected = selectedTemplate === template.id;
            return (
              <button
                key={template.id}
                type="button"
                onClick={() => setSelectedTemplate(template.id)}
                className={[
                  "flex flex-col gap-3 rounded-lg border-2 p-3 text-left transition-colors",
                  isSelected
                    ? "border-primary bg-primary/5"
                    : "border-border hover:border-muted-foreground/40",
                ].join(" ")}
              >
                <div className="w-full aspect-video rounded overflow-hidden">
                  {template.diagram}
                </div>
                <div className="flex flex-col gap-0.5">
                  <p className="text-sm font-semibold">{template.name}</p>
                  <p className="text-xs text-muted-foreground">{template.description}</p>
                </div>
              </button>
            );
          })}
        </div>
      </div>

      {activeTemplate && (
        <div className="flex flex-col gap-2">
          <p className="text-sm font-medium">Zones</p>
          <ul className="list-disc list-inside flex flex-col gap-1">
            {activeTemplate.zones.map((zone) => (
              <li key={zone} className="text-sm text-muted-foreground">
                {zone}
              </li>
            ))}
          </ul>
        </div>
      )}

      <div className="flex items-center gap-3">
        <Button asChild variant="outline">
          <Link href="/layouts">Cancel</Link>
        </Button>
        <Button disabled>Save Layout</Button>
      </div>
    </div>
  );
}
